sys_script.script:
(function executeRule(current, previous) {

    var admissionGR = current.admission_request.getRefRecord();

    if (!admissionGR.isValidRecord())
        return;

    var programGR = admissionGR.program.getRefRecord();

    var year = new GlideDateTime().getYearLocalTime();

    var countGR = new GlideRecord('x_1920756_univer_0_admission_request');
    countGR.addQuery('program', admissionGR.program);
    countGR.addNotNullQuery('student_number');
    countGR.query();

    var sequence = countGR.getRowCount() + 1;

    var seqStr = ('0000' + sequence).slice(-4);

    var studentNumber = year + '-' +
                        programGR.program_code + '-' +
                        seqStr;

    admissionGR.student_number = studentNumber;

    admissionGR.university_email =
        studentNumber.toLowerCase() +
        '@students.university.edu';

    admissionGR.status_field = 'provisioning';

    admissionGR.update();

    var cardGR = new GlideRecord('x_1920756_univer_0_student_id_card');

    cardGR.initialize();

    cardGR.admission_request = admissionGR.sys_id;

    cardGR.card_number = 'ID-' + studentNumber;

    cardGR.issue_date = new GlideDate();

    cardGR.print_status = 'queued';

    cardGR.insert();

})(current, previous);
